from __future__ import annotations
from typing import Any
def build_dashboard_ready_summary(store:dict[str,Any], windows:list[dict[str,Any]], evaluation:dict[str,Any], calibration:dict[str,Any], factor:dict[str,Any], sample_mode:bool)->dict[str,Any]:
    gaps=store.get('completeness_summary',{}).get('by_artifact_type',{}).get('missing',[])
    return {"summary_status":"sample_demo" if sample_mode else ("partial" if store.get('records') else "not_available"),"real_history_available":not sample_mode and bool(store.get('records')),"sample_mode":sample_mode,"rolling_windows":[w.get('window_id') for w in windows],"key_metrics":{"evaluation_status":evaluation.get('status'),"calibration_status":calibration.get('calibration_status'),"factor_status":factor.get('factor_effectiveness_status')},"data_gaps":gaps,"pending_reviews":store.get('completeness_summary',{}).get('findings',{}).get('pending_count',0),"diagnostics":{"insufficient_real_history": sample_mode or evaluation.get('status') in {'insufficient','not_available'}},"recommended_operator_actions":["activate controlled artifact retention in future AI-DEV-130"],"advisory_only":True,"production_publish_allowed":False}
